refsection.programlisting:
mask = zeros(150, 260) == 1;
mask(25:44, 20:39) = %t;
mask(25:74, 90:139) = %t;
mask(25:104, 180:239) = %t;

selected = imbwpropfilt(mask, "area", [1000 3000]);

subplot(1, 2, 1);
imshow(uint8(mask .* 255));
xtitle("All components: areas 400, 2500, and 4800");
subplot(1, 2, 2);
imshow(uint8(selected .* 255));
xtitle("Area from 1000 to 3000: middle object retained");

mask = zeros(130, 220) == 1;
mask(25:74, 25:74) = %t;
mask(25:94, 130:139) = %t;
mask(85:94, 130:199) = %t;

compact = imbwpropfilt(mask, "extent", [0.8 1]);

subplot(1, 2, 1);
imshow(uint8(mask .* 255));
xtitle("Filled square and sparse L-shaped component");
subplot(1, 2, 2);
imshow(uint8(compact .* 255));
xtitle("Extent from 0.8 to 1.0: compact object retained");
